// Generic Lexer Framework
// ============================================================================

// Emit a syntax span with bounds checking
// Defined once here to avoid duplication across language lexers
#define EMIT_SPAN(out_spans, span_count, max_spans, start_pos, len, tok) do { \
    if ((span_count) < (max_spans) && (len) > 0) { \
        (out_spans)[(span_count)].start = (uint16_t)(start_pos); \
        (out_spans)[(span_count)].length = (uint16_t)(len); \
        (out_spans)[(span_count)].token = (tok); \
        (span_count)++; \
    } \
} while(0)

// Lexer configuration for a language
struct LexerConfig {
    // Keyword/type tables
    const char* const* keywords;
    const char* const* types;
    size_t keyword_count;
    size_t type_count;

    // Comment markers
    const char* block_comment_start;     // e.g., "/*" or "<!--"
    size_t block_comment_start_len;      // Length of start marker
    const char* block_comment_end;       // e.g., "*/" or "-->"
    const char* line_comment;            // e.g., "//" or nullptr

    // String literal configuration
    struct {
        char start;              // Opening quote
        char escape;             // Escape character (0 if no escapes)
        bool verbatim;           // @"..." style (doubled quotes)
    } string_delims[4];         // Support multiple quote styles
    size_t string_delim_count;

    // Number literal support flags
    bool hex_enabled;
    bool binary_enabled;
    bool underscore_sep;
    bool float_suffixes;
    bool int_suffixes;

    // Language features
    bool has_attributes;        // C#[...]
    bool has_preprocessor;      // C++ #
    bool has_raw_strings;       // C++ R"(...)"
    bool has_interpolated;      // C# $"..."
    bool has_tag_syntax;        // XML/XAML <tags>
    bool has_typename_dots;     // Allow dots in identifiers (XAML namespaces)
};

