// ============================================================================
// Generic Lexer Implementation
// ============================================================================

// Tokenize a single line using a language configuration
// Returns number of spans written
static size_t lex_generic_line(
    const char* line,
    SyntaxSpan* out_spans,
    size_t max_spans,
    bool* lexer_state,
    const LexerConfig* config
) {
    if (!line || !out_spans || max_spans == 0) return 0;

    size_t span_count = 0;
    const char* p = line;
    const char* line_start = line;

    // Handle continuation of block comment from previous line
    if (*lexer_state && config->block_comment_end) {
        const char* end = strstr(p, config->block_comment_end);
        if (end) {
            size_t len = (end - p) + strlen(config->block_comment_end);
            EMIT_SPAN(out_spans, span_count, max_spans, 0, len, SyntaxToken::Comment);
            p = end + strlen(config->block_comment_end);
            *lexer_state = false;
        } else {
            // Entire line is still in comment
            EMIT_SPAN(out_spans, span_count, max_spans, 0, strlen(line), SyntaxToken::Comment);
            return span_count;
        }
    }

    while (*p) {
        size_t pos = p - line_start;

        // Skip whitespace (no span needed)
        if (is_whitespace(*p)) {
            p++;
            continue;
        }

        // Line comment
        if (config->line_comment && p[0] == config->line_comment[0] && p[1] == config->line_comment[1]) {
            size_t len = strlen(p);
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Comment);
            break;  // Rest of line is comment
        }

        // Block comment start
        if (config->block_comment_start &&
            strncmp(p, config->block_comment_start, config->block_comment_start_len) == 0) {
            const char* end = strstr(p + config->block_comment_start_len, config->block_comment_end);
            if (end) {
                size_t len = (end - p) + strlen(config->block_comment_end);
                EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Comment);
                p = end + strlen(config->block_comment_end);
            } else {
                // Comment extends to next line
                EMIT_SPAN(out_spans, span_count, max_spans, pos, strlen(p), SyntaxToken::Comment);
                *lexer_state = true;
                break;
            }
            continue;
        }

        // Preprocessor directive
        if (config->has_preprocessor && *p == '#') {
            size_t len = strlen(p);
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Preprocessor);
            break;
        }

        // String literal (check each configured delimiter)
        bool is_string = false;
        char quote = 0;
        for (size_t i = 0; i < config->string_delim_count; i++) {
            if (*p == config->string_delims[i].start) {
                is_string = true;
                quote = config->string_delims[i].start;
                break;
            }
        }

        if (is_string) {
            const char* start = p;
            p++;

            // Handle special string prefixes
            bool verbatim = false;
            bool interpolated = false;
            if (*(p - 1) == '@' || *(p - 1) == '$') {
                if (*(p - 1) == '@') verbatim = true;
                if (*(p - 1) == '$') interpolated = true;
                if (*p == '"' && *(p + 1) == '"') {
                    // $@"..." combined
                    verbatim = true;
                    p++;
                }
            }

            // Find closing quote
            while (*p) {
                if (verbatim) {
                    if (*p == '"') {
                        if (p[1] == '"') {
                            p += 2;  // Escaped quote
                        } else {
                            p++;
                            break;
                        }
                    } else {
                        p++;
                    }
                } else if (*p == '\\' && p[1]) {
                    p += 2;  // Skip escape sequence
                } else if (*p == quote) {
                    p++;
                    break;
                } else {
                    p++;
                }
            }

            size_t len = p - start;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::String);
            continue;
        }

        // Raw string literal R"(...)" (C++ specific)
        if (config->has_raw_strings && *p == 'R' && p[1] == '"') {
            const char* start = p;
            p += 2;
            const char* delim_start = p;
            while (*p && *p != '(') p++;
            size_t delim_len = p - delim_start;
            if (*p == '(') p++;

            while (*p) {
                if (*p == ')') {
                    if (strncmp(p + 1, delim_start, delim_len) == 0 &&
                        p[1 + delim_len] == '"') {
                        p += 2 + delim_len;
                        break;
                    }
                }
                p++;
            }
            size_t len = p - start;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::String);
            continue;
        }

        // Number literal
        if (is_digit(*p) || (*p == '.' && is_digit(p[1]))) {
            const char* start = p;

            // Hex prefix
            if (config->hex_enabled && p[0] == '0' && (p[1] == 'x' || p[1] == 'X')) {
                p += 2;
                while (is_hex_digit(*p) || (config->underscore_sep && *p == '\'') || *p == '\'') p++;
            }
            // Binary prefix
            else if (config->binary_enabled && p[0] == '0' && (p[1] == 'b' || p[1] == 'B')) {
                p += 2;
                while (*p == '0' || *p == '1' || (config->underscore_sep && *p == '_')) p++;
            }
            // Decimal/float
            else {
                while (is_digit(*p) || (config->underscore_sep && *p == '_')) p++;
                if (*p == '.') {
                    p++;
                    while (is_digit(*p) || (config->underscore_sep && *p == '_')) p++;
                }
                // Exponent
                if (*p == 'e' || *p == 'E') {
                    p++;
                    if (*p == '+' || *p == '-') p++;
                    while (is_digit(*p)) p++;
                }
            }

            // Suffixes
            if (config->float_suffixes || config->int_suffixes) {
                while (true) {
                    char c = *p;
                    if (c == 'u' || c == 'U' || c == 'l' || c == 'L') {
                        if (config->int_suffixes) {
                            p++;
                            if (c == 'l' && (*p == 'l' || *p == 'L')) p++;  // ll suffix
                            continue;
                        }
                    }
                    if ((c == 'f' || c == 'F' || c == 'd' || c == 'D') && config->float_suffixes) {
                        p++;
                        continue;
                    }
                    if (c == 'm' || c == 'M') {  // decimal suffix
                        p++;
                        continue;
                    }
                    break;
                }
            }

            size_t len = p - start;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Number);
            continue;
        }

        // Attribute [...] (C# specific)
        if (config->has_attributes && *p == '[') {
            const char* start = p;
            p++;
            int depth = 1;
            while (*p && depth > 0) {
                if (*p == '[') depth++;
                else if (*p == ']') depth--;
                p++;
            }
            size_t len = p - start;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Attribute);
            continue;
        }

        // Tag syntax <...> (XAML specific)
        if (config->has_tag_syntax && *p == '<') {
            const char* tag_start = p;
            p++;
            if (*p == '/') p++;  // Closing tag
            if (*p == '?') p++;  // XML declaration
            if (*p == '!') p++;  // DOCTYPE etc

            // Read tag name (allow dots for namespaces)
            const char* name_start = p;
            while (*p && (is_ident_char(*p) || *p == ':' || (config->has_typename_dots && *p == '.'))) p++;

            if (p > name_start) {
                size_t tag_len = p - tag_start;
                EMIT_SPAN(out_spans, span_count, max_spans, pos, tag_len, SyntaxToken::Tag);
            }
            continue;
        }

        // Tag end > or />
        if (config->has_tag_syntax && (*p == '>' || (*p == '/' && p[1] == '>'))) {
            size_t len = (*p == '/') ? 2 : 1;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Tag);
            p += len;
            continue;
        }

        // Identifier or keyword
        if (is_ident_start(*p)) {
            const char* start = p;
            while (is_ident_char(*p)) p++;
            size_t len = p - start;

            if (config->keywords && len < Syntax::MAX_IDENTIFIER_LEN) {
                char ident[Syntax::MAX_IDENTIFIER_LEN];
                memcpy(ident, start, len);
                ident[len] = '\0';

                SyntaxToken tok = SyntaxToken::Default;
                if (is_in_table(ident, config->keywords, config->keyword_count)) {
                    tok = SyntaxToken::Keyword;
                } else if (is_in_table(ident, config->types, config->type_count)) {
                    tok = SyntaxToken::Type;
                }

                if (tok != SyntaxToken::Default) {
                    EMIT_SPAN(out_spans, span_count, max_spans, pos, len, tok);
                }
            }
            continue;
        }

        // Punctuation and other characters
        p++;
    }

    return span_count;
}

// ============================================================================
// C/C++ Lexer
// ============================================================================

// Tokenize a single line of C/C++ code
// Returns number of spans written
static size_t tokenize_cpp_line(
    const char* line,
    SyntaxSpan* out_spans,
    size_t max_spans,
    bool* in_block_comment
) {
    return lex_generic_line(line, out_spans, max_spans, in_block_comment, &g_cpp_config);
}

