// Tokenize a single line of C# code
static size_t tokenize_csharp_line(
    const char* line,
    SyntaxSpan* out_spans,
    size_t max_spans,
    bool* in_block_comment
) {
    return lex_generic_line(line, out_spans, max_spans, in_block_comment, &g_csharp_config);
}

// ============================================================================
// XAML Lexer
// ============================================================================

// Tokenize a single line of XAML/XML
static size_t tokenize_xaml_line(
    const char* line,
    SyntaxSpan* out_spans,
    size_t max_spans,
    bool* in_block_comment
) {
    if (!line || !out_spans || max_spans == 0) return 0;

    size_t span_count = 0;
    const char* p = line;
    const char* line_start = line;

    // Handle continuation of block comment from previous line
    if (*in_block_comment) {
        const char* end = strstr(p, "-->");
        if (end) {
            size_t len = (end - p) + 3;
            EMIT_SPAN(out_spans, span_count, max_spans, 0, len, SyntaxToken::Comment);
            p = end + 3;
            *in_block_comment = false;
        } else {
            EMIT_SPAN(out_spans, span_count, max_spans, 0, strlen(line), SyntaxToken::Comment);
            return span_count;
        }
    }

    while (*p) {
        size_t pos = p - line_start;

        if (is_whitespace(*p)) {
            p++;
            continue;
        }

        // XML comment <!-- -->
        if (p[0] == '<' && p[1] == '!' && p[2] == '-' && p[3] == '-') {
            const char* end = strstr(p + 4, "-->");
            if (end) {
                size_t len = (end - p) + 3;
                EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Comment);
                p = end + 3;
            } else {
                EMIT_SPAN(out_spans, span_count, max_spans, pos, strlen(p), SyntaxToken::Comment);
                *in_block_comment = true;
                break;
            }
            continue;
        }

        // Tag start < or </
        if (*p == '<') {
            const char* tag_start = p;
            p++;
            if (*p == '/') p++;  // Closing tag
            if (*p == '?') p++;  // XML declaration
            if (*p == '!') p++;  // DOCTYPE etc

            // Read tag name
            const char* name_start = p;
            while (*p && (is_ident_char(*p) || *p == ':' || *p == '.')) p++;

            if (p > name_start) {
                size_t tag_len = p - tag_start;
                EMIT_SPAN(out_spans, span_count, max_spans, pos, tag_len, SyntaxToken::Tag);
            }
            continue;
        }

        // Tag end > or />
        if (*p == '>' || (*p == '/' && p[1] == '>')) {
            size_t len = (*p == '/') ? 2 : 1;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Tag);
            p += len;
            continue;
        }

        // Attribute name (before =) - XAML-specific detection
        if (is_ident_start(*p) || *p == ':') {
            const char* start = p;
            while (*p && (is_ident_char(*p) || *p == ':' || *p == '.')) p++;

            // Check if followed by = (it's an attribute)
            const char* after = p;
            while (*after == ' ' || *after == '\t') after++;
            if (*after == '=') {
                size_t len = p - start;
                EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::Attribute);
            }
            continue;
        }

        // String literals (handled by generic config)
        bool is_string = false;
        for (size_t i = 0; i < g_xaml_config.string_delim_count; i++) {
            if (*p == g_xaml_config.string_delims[i].start) {
                is_string = true;
                break;
            }
        }
        if (is_string) {
            const char* start = p;
            p++;
            while (*p && *p != start[0]) p++;
            if (*p == start[0]) p++;
            size_t len = p - start;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::String);
            continue;
        }

        p++;
    }

    return span_count;
}

// ============================================================================
// Markdown Lexer
// ============================================================================

// Tokenize a single line of Markdown
static size_t tokenize_markdown_line(
    const char* line,
    SyntaxSpan* out_spans,
    size_t max_spans,
    bool* in_code_block
) {
    if (!line || !out_spans || max_spans == 0) return 0;

    size_t span_count = 0;
    const char* p = line;
    const char* line_start = line;
    size_t line_len = strlen(line);

    // Check for code block fence
    if (strncmp(line, "```", 3) == 0) {
        *in_code_block = !*in_code_block;
        EMIT_SPAN(out_spans, span_count, max_spans, 0, line_len, SyntaxToken::MarkdownCode);
        return span_count;
    }

    // Inside code block - entire line is code
    if (*in_code_block) {
        EMIT_SPAN(out_spans, span_count, max_spans, 0, line_len, SyntaxToken::MarkdownCode);
        return span_count;
    }

    // Skip leading whitespace
    while (*p == ' ' || *p == '\t') p++;

    // Heading: # ## ### etc at line start
    if (*p == '#') {
        EMIT_SPAN(out_spans, span_count, max_spans, 0, line_len, SyntaxToken::MarkdownHeading);
        return span_count;
    }

    // Now scan for inline elements
    p = line;
    while (*p) {
        size_t pos = p - line_start;

        // Inline code `...`
        if (*p == '`') {
            const char* start = p;
            p++;
            while (*p && *p != '`') p++;
            if (*p == '`') p++;
            size_t len = p - start;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::MarkdownCode);
            continue;
        }

        // Bold **...** or __...__
        if ((*p == '*' && p[1] == '*') || (*p == '_' && p[1] == '_')) {
            char marker = *p;
            const char* start = p;
            p += 2;
            // Find closing marker
            while (*p) {
                if (*p == marker && p[1] == marker) {
                    p += 2;
                    break;
                }
                p++;
            }
            size_t len = p - start;
            EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::MarkdownBold);
            continue;
        }

        // Italic *...* or _..._ (single marker)
        if (*p == '*' || *p == '_') {
            char marker = *p;
            const char* start = p;
            p++;
            // Find closing marker (not doubled)
            while (*p) {
                if (*p == marker && (p[1] != marker)) {
                    p++;
                    break;
                }
                if (*p == marker && p[1] == marker) {
                    // This is bold, not our closing
                    break;
                }
                p++;
            }
            size_t len = p - start;
            if (len > 2) {  // At least *x*
                EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::MarkdownItalic);
            }
            continue;
        }

        // Link [text](url)
        if (*p == '[') {
            const char* start = p;
            p++;
            // Find ]
            while (*p && *p != ']') p++;
            if (*p == ']' && p[1] == '(') {
                p += 2;
                // Find )
                while (*p && *p != ')') p++;
                if (*p == ')') p++;
                size_t len = p - start;
                EMIT_SPAN(out_spans, span_count, max_spans, pos, len, SyntaxToken::MarkdownLink);
                continue;
            }
            // Not a link - bail out if we hit end of string while scanning for ']',
            // otherwise the outer p++ would walk past the null terminator.
            if (*p == '\0') break;
            // Otherwise continue from current position (skip the unmatched '[').
        }

        p++;
    }

    return span_count;
}

// ============================================================================
// Unified Tokenization Entry Point
// ============================================================================

// Tokenize a line based on file type
// Returns number of spans written
size_t syntax_tokenize_line(
    const char* line,
    FileType file_type,
    SyntaxSpan* out_spans,
    size_t max_spans,
    bool* lexer_state  // Per-file state (block comments, code blocks, etc.)
) {
    if (!line || file_type == FileType::Unknown || !out_spans) return 0;
    
    bool dummy_state = false;
    bool* state_ptr = lexer_state ? lexer_state : &dummy_state;
    
    switch (file_type) {
        case FileType::Cpp:
        case FileType::Header:
            return tokenize_cpp_line(line, out_spans, max_spans, state_ptr);
        
        case FileType::CSharp:
            return tokenize_csharp_line(line, out_spans, max_spans, state_ptr);
        
        case FileType::Xaml:
            return tokenize_xaml_line(line, out_spans, max_spans, state_ptr);
        
        case FileType::Markdown:
            return tokenize_markdown_line(line, out_spans, max_spans, state_ptr);
        
        default:
            return 0;
    }
}
